    if (!_blob) { return; }
    int32_t _len = (int32_t)item.size;
    memcpy(_blob, &_len, 4);
    if (item.size > 0) { memcpy(_blob + 4, item.data, item.size); }
    obj.type = Dart_CObject_kInt64;
    obj.value.as_int64 = (intptr_t)_blob;
    if (!Dart_PostCObject_DL(port, &obj)) {
        g_port_configStream = 0;
        free(_blob);
        return;
    }
}

